        let _TEMP4 /* SDAI.LOGICAL */ = _TEMP1 && _TEMP3
        let _TEMP5 /* SDAI.LOGICAL */ = SDAI.TYPEOF( SELF.REPRESENTED_TOPOLOGY, 
          IS: eKINEMATIC_TOPOLOGY_DIRECTED_STRUCTURE.self )
        let _TEMP6 /* runtime? */ = /*runtime*/SELF.REPRESENTED_TOPOLOGY?.ITEMS
        let _TEMP7 /* SDAI.SET<eKINEMATIC_JOINT.PRef>? */ = GET_KINEMATIC_JOINTS_FROM_ORIENTED_JOINTS( 
            SDAI.SET<eORIENTED_JOINT.PRef>(/*runtime*/_TEMP6) )
        let _TEMP8 /* SDAI.LOGICAL */ = SELF.REPRESENTED_JOINTS .===. _TEMP7
        let _TEMP9 /* SDAI.LOGICAL */ = _TEMP5 && _TEMP8
        let _TEMP10 /* SDAI.LOGICAL */ = _TEMP4 || _TEMP9
        let _TEMP11 /* SDAI.LOGICAL */ = SDAI.TYPEOF( SELF.REPRESENTED_TOPOLOGY, 
          IS: eKINEMATIC_TOPOLOGY_NETWORK_STRUCTURE.self )
        let _TEMP12 /* runtime? */ = /*runtime*/SELF.REPRESENTED_TOPOLOGY?.ITEMS
        let _TEMP13 /* SDAI.SET<eKINEMATIC_JOINT.PRef>? */ = GET_KINEMATIC_JOINTS_FROM_KINEMATIC_LOOPS( 
            SDAI.SET<eKINEMATIC_LOOP.PRef>(/*runtime*/_TEMP12) )
        let _TEMP14 /* SDAI.LOGICAL */ = SELF.REPRESENTED_JOINTS .===. _TEMP13
        let _TEMP15 /* SDAI.LOGICAL */ = _TEMP11 && _TEMP14
        let _TEMP16 /* SDAI.LOGICAL */ = _TEMP10 || _TEMP15
        return _TEMP16
      }

      //EXPRESS IMPLICIT PARTIAL ENTITY CONSTRUCTOR
      /// initialize from explicit attribute values
      public init(REPRESENTED_TOPOLOGY: sKINEMATIC_TOPOLOGY_REPRESENTATION_SELECT) {

        self._represented_topology = REPRESENTED_TOPOLOGY

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( REPRESENTED_TOPOLOGY: original._represented_topology )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 1
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: 
          sKINEMATIC_TOPOLOGY_REPRESENTATION_SELECT.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]REPRESENTED_TOPOLOGY for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( REPRESENTED_TOPOLOGY: p0 )
      }
    }
  }
}
